const root = $input.first().json;
const body = root.body ?? root;
const creds =
  typeof body.credentials === 'object' && body.credentials !== null
    ? body.credentials
    : {};

const userIdRaw =
  body.user_id ?? body.userId ?? creds.user_id ?? creds.userId;
if (
  userIdRaw === undefined ||
  userIdRaw === null ||
  String(userIdRaw).trim() === ''
) {
  throw new Error(
    'Missing user_id: send user_id or userId in the webhook body or credentials.',
  );
}

function sanitizeSlug(s) {
  let t = String(s)
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '');
  if (!t) t = 'user';
  if (t.length > 48) t = t.slice(0, 48).replace(/-+$/, '');
  return t;
}

const slug = sanitizeSlug(userIdRaw);

const vmId = String(
  creds.HOSTINGER_VPS_ID ?? body.HOSTINGER_VPS_ID ?? '1433354',
);

const projectName = String(
  creds.PROJECT_NAME ?? body.project_name ?? `veratex-openclaw-${slug}`,
);

const containerName = `veratex_openclaw_${slug}`.replace(
  /[^a-zA-Z0-9_.-]/g,
  '_',
);

const composeYaml = `services:
  openclaw:
    image: ghcr.io/hostinger/hvps-openclaw:latest
    container_name: ${containerName}
    restart: unless-stopped
    ports:
      - \${PORT}:\${PORT}
    env_file:
      - .env
    volumes:
      - ./data:/data
      - ./gog:/usr/local/bin/gog:ro
`;

function formatEnvValue(val) {
  const s = String(val ?? '');
  if (/[\n\r"#=\s]/.test(s)) {
    return (
      '"' +
      s.replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/\n/g, '\\n') +
      '"'
    );
  }
  return s;
}

const RESERVED = new Set([
  'HOSTINGER_VPS_ID',
  'user_id',
  'userId',
  'project_name',
  'PROJECT_NAME',
  'container_name',
  'credentials',
  'env',
]);

const merged = {};
function mergeFlat(obj) {
  if (!obj || typeof obj !== 'object' || Array.isArray(obj)) return;
  for (const [k, v] of Object.entries(obj)) {
    if (RESERVED.has(k)) continue;
    if (v === undefined) continue;
    if (typeof v === 'object' && v !== null && !Array.isArray(v)) continue;
    merged[k] = v;
  }
}

mergeFlat(body);
mergeFlat(creds);
if (body.env && typeof body.env === 'object' && !Array.isArray(body.env)) {
  mergeFlat(body.env);
}

if (
  !Object.prototype.hasOwnProperty.call(merged, 'PORT') ||
  String(merged.PORT ?? '').trim() === ''
) {
  throw new Error(
    'Missing PORT: Lovable must send PORT in the payload (body, credentials, or env). n8n does not set a default.',
  );
}

const environment = Object.keys(merged)
  .sort()
  .map((key) => key + '=' + formatEnvValue(merged[key]))
  .join('\n');

return [
  {
    json: {
      vm_id: vmId,
      project_name: projectName,
      content: composeYaml,
      environment,
    },
  },
];
